                    message = "璇蜂繚鎸佹垝鎸囦僵鎴寸ǔ瀹氾紝姝ｅ湪娴嬮噺${type.displayName()}",
                )
            }
            val progressJob = launch {
                listOf(32, 55, 76, 92).forEach { progress ->
                    delay(1_500)
                    mutableUiState.update { it.copy(syncProgress = progress) }
                }
            }
            runCatching { repository.measure(type) }
                .onSuccess { result ->
                    progressJob.cancel()
                    mutableUiState.update {
                        it.copy(
                            isSyncing = false,
                            measuringMetric = null,
                            syncProgress = 100,
                            lastSyncAt = result.completedAt,
                            message = if (result.recordsWritten > 0) {
                                "${type.displayName()}娴嬮噺瀹屾垚锛岀粨鏋滃凡淇濆瓨"
                            } else {
                                "娌℃湁璇诲彇鍒?{type.displayName()}缁撴灉锛岃閲嶆柊娴嬮噺"
                            },
                        )
                    }
                }
                .onFailure { error ->
                    progressJob.cancel()
                    mutableUiState.update {
                        it.copy(
                            isSyncing = false,
